INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('cc7c5ebdbaa03915', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Do I need a campaign treasurer even if I don''t raise money?', '["When do I have to appoint a campaign treasurer?","Do I need a treasurer before fundraising?","Can I spend my own money before filing a treasurer appointment?"]', 'Yes. You must file a Campaign Treasurer Appointment (Form CTA) with the appropriate authority before you can accept any contributions, make any expenditures, or even publicly announce your candidacy for office.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Campaign Treasurer FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates seeking state, district, county, or local office in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('d2da327fa252c941', 'TX', '["federal","state","district","county","local"]', 'election_dates', 'When is the 2026 Primary Runoff and when does early voting start?', '["What is the date of the primary runoff?","When can I start voting in the runoff?","Runoff election dates 2026"]', 'The 2026 Primary Runoff Election Day is Tuesday, May 26, 2026. Early voting for the runoff begins on Monday, May 18, 2026, and ends on Friday, May 22, 2026.', 'https://www.sos.state.tx.us/elections/voter/important-election-dates.shtml', 'Texas Secretary of State – Important Election Dates', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all Texas voters and candidates with primary runoffs on the ballot.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('078773413cc3e26a', 'TX', '["state","district","county","local"]', 'ballot_access', 'If I lost my primary, can I run as an independent in the general election?', '["Does Texas have a sore loser law?","Can a primary loser run in November?","Can I be a write-in after losing a primary?"]', 'No. Under Texas Election Code § 162.015, a person who was a candidate in a primary election is ineligible to be an independent candidate or a write-in candidate for that same office in the succeeding general election.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.162.htm#162.015', 'Texas Election Code § 162.015', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates who participated in a primary election cycle.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('7347b02cee11bd44', 'TX', '["state","district"]', 'residency', 'How long do I have to live in my district before I can run for State Representative?', '["What are the residency requirements for State House?","How long must I be a resident of my district?","Residency rules for TX House candidates"]', 'A candidate for State Representative must have lived in Texas for two years and in the specific district for one year immediately preceding the date of the election.', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/qualifications2026.shtml', 'Texas Secretary of State – Candidate Qualifications 2026', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates for the Texas House of Representatives.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('6ccc376b8f598d4f', 'TX', '["local"]', 'ballot_access', 'What is the filing fee to run for a municipal office like City Council?', '["How much does it cost to file for city office?","Where do I find municipal filing fees?","Are there fees for nonpartisan local races?"]', 'Municipal filing fees are not set by state law but are determined by individual city charters. Candidates must contact their City Secretary''s office or consult the specific City Charter for the local filing fee or petition requirements.', 'https://www.sos.state.tx.us/elections/laws/faq-on-local-candidacy.shtml', 'Texas Secretary of State – FAQ on Local Candidacy', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates seeking municipal (city) office.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('6195cd8f62f2935b', 'TX', '["federal","state","district","county","local"]', 'ballot_access', 'Can I use a nickname on the ballot?', '["How do I list a nickname on my application?","What are the rules for ballot names?","Can I use my professional title as a nickname?"]', 'A candidate may use one unhyphenated word of up to 10 letters as a nickname if they have been commonly known by it for at least three years; however, slogans or titles like ''Doctor'' or ''Pastor'' are prohibited.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.52.htm#52.031', 'Texas Election Code § 52.031', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates appearing on a Texas ballot.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('b3f457835a8a85cc', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I use my personal credit card for campaign expenses?', '["How do I report personal credit card use?","Can the campaign pay me back for things I bought on my card?","Personal credit card for campaign supplies?"]', 'Yes, but you must report the expenditure as ''payment from personal funds'' and then report the campaign''s reimbursement to you as a separate transaction on your finance report.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Campaign Finance FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates/officeholders who use personal credit for campaign purposes.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('4bf83b9bf6527f63', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Is there a limit on how much of my own money I can loan to my campaign?', '["What is the cap on candidate loans?","Can I loan my campaign $100k?","Limit on personal loans to campaign?"]', 'While there is no limit on the amount you can loan your campaign, there are strict limits on how much of those loans can be repaid from political contributions—specifically $250,000 for statewide offices and $25,000 for other offices.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.042', 'Texas Election Code § 253.042', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates for state and district offices seeking to repay loans from contributions.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('c20b1c4637348940', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I accept a contribution from a corporation?', '["Are corporate donations legal in Texas?","Can a company write my campaign a check?","Can my LLC donate to my campaign?"]', 'No. Texas law strictly prohibits candidates and officeholders from accepting political contributions from corporations or labor organizations.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.094', 'Texas Election Code § 253.094', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('0b2de00342d43154', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I accept cash contributions?', '["Is there a limit on cash donations?","Can someone give me $100 in cash?","Cash contribution rules in Texas"]', 'A candidate or officeholder may not accept more than $100 in cash (currency) from a single contributor during a reporting period.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.033', 'Texas Election Code § 253.033', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('501d42b80061dfc0', 'TX', '["state","district","county","local"]', 'finance_ethics', 'When do I have to itemize a donation on my report?', '["What is the disclosure threshold for donors?","Do I have to list every person who gives me $5?","At what dollar amount must I list a donor''s name?"]', 'You must itemize (list the name and address) for any contributor who gives you more than $110 in the aggregate during a reporting period for state/district races ($50 for some local jurisdictions).', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Reporting FAQ', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all candidates/officeholders filing with the Texas Ethics Commission.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('6799d83653c9eab6', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I use campaign funds to buy a suit for a debate?', '["Is clothing a permissible campaign expense?","Can I pay for a tuxedo with campaign money?","Personal use rules for campaign funds"]', 'No. Campaign funds may not be used for personal expenses, which includes clothing that is suitable for ordinary everyday use outside of campaign activities.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.035', 'Texas Election Code § 253.035', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('8586a43e7e0df687', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Do I have to include a disclosure ''disclaimer'' on my campaign signs?', '["Political advertising disclosure rules?","Does my yard sign need to say who paid for it?","Disclosure requirements for flyers"]', 'Yes. Most political advertising must include a disclosure statement that identifies the person or entity that paid for the advertising or the candidate/committee that authorized it.', 'https://www.ethics.state.tx.us/resources/advertising/PolAd_Guide.php', 'Texas Ethics Commission – Political Advertising Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to all political advertising in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('9147a43c5789d57b', 'TX', '["state","district","county","local"]', 'candidate_eligibility', 'Can I run for office if I have a past felony conviction?', '["Felony rules for TX candidates","Can a felon run for office in Texas?","Restoration of rights for running for office"]', 'A person convicted of a felony is ineligible to run for office unless they have been pardoned or otherwise released from the resulting disabilities of the conviction (e.g., completed all terms of their sentence, including parole).', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.141.htm#141.001', 'Texas Election Code § 141.001', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates for public office in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('b43510c670d165cb', 'TX', '["state","district","county","local"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late?', '["How much is the fine for late filing?","What happens if I miss a reporting deadline?","Late filing penalties Texas Ethics Commission"]', 'The penalty for late filing varies based on the report type but generally starts at $500 for the first day and increases by $100 per day thereafter, potentially up to $10,000 for serious violations.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Late Filing FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates/officeholders required to file reports with the TEC.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('1bc3fc75cbe24893', 'TX', '["state","district"]', 'residency', 'Does my residency clock ''reset'' if my district lines changed during redistricting?', '["Redistricting impact on residency","How do redrawn lines affect my 1-year residency?","Residency requirements after a new map"]', 'No. Under Texas law, if a district is redrawn, the time you resided in your previous district counts toward the residency requirement of the new district that now encompasses your home.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.141.htm#141.001', 'Texas Election Code § 141.001', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates affected by the 2021/2022 redistricting cycle.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('eda60cdb29a4dfd2', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I accept a contribution from a foreign national?', '["Can non-citizens donate to my campaign?","Foreign national donation rules","Are contributions from green card holders allowed?"]', 'No. Federal and state law prohibit candidates from accepting contributions from foreign nationals, though ''green card'' holders (Permanent Residents) are generally allowed to contribute.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Foreign Nationals FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('d2166b756d3a5334', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I use campaign funds to pay for my campaign''s office rent?', '["Are office leases a valid campaign expense?","Can I rent a campaign HQ with donor money?","Permissible campaign rent payments"]', 'Yes. Campaign funds may be used for any ordinary and necessary expense of the campaign, which includes the rental of office space for campaign headquarters.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.035', 'Texas Election Code § 253.035', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('7f1851ab36dd4b67', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I give campaign funds to a charity?', '["Donating campaign money to non-profits","Can my campaign give to a 501(c)(3)?","Charitable donations from political accounts"]', 'Yes. Campaign funds may be used to make a contribution to a charitable organization, provided the candidate does not receive a personal benefit from the donation.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.035', 'Texas Election Code § 253.035', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('3eab5ec42bedd283', 'TX', '["state","district","county","local"]', 'finance_ethics', 'How long must I keep records of my campaign finances?', '["Record keeping requirements for TX campaigns","How long do I save receipts for campaign stuff?","Candidate record retention rules"]', 'Candidates and officeholders are required to maintain all campaign records, including receipts and bank statements, for at least two years after the filing deadline for the report to which the record relates.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.254.htm#254.001', 'Texas Election Code § 254.001', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('c153356d7e166471', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'How far away must I be from a polling place when electioneering?', '["What is the distance for campaign signs at polls?","How far from the door can I stand to hand out cards?","Polling place distance rules Texas"]', 'Under Texas law, no person may electioneer or hand out campaign materials within 100 feet of an outside door through which a voter may enter a building in which a polling place is located.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.61.htm#61.003', 'Texas Election Code § 61.003', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates, supporters, and electioneers in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('0e62e61debf39a37', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I pay my spouse a salary from my campaign funds?', '["Can I hire my family for the campaign?","Paying relatives with campaign money","Nepotism rules for campaign staff"]', 'No. A candidate or officeholder may not use political contributions to pay for personal services rendered by the candidate''s spouse or dependent children.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.041', 'Texas Election Code § 253.041', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('48368cb140d8f382', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Do I have to itemize the occupation and employer of my donors?', '["Reporting donor job info","What info do I need from people who give money?","Do I need to ask for a contributor''s employer?"]', 'Yes. For candidates filing with the Texas Ethics Commission, you must provide the occupation and employer for any individual who contributes more than $1,010 in the aggregate during a reporting period.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Reporting FAQ', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to statewide and district-level candidates/officeholders.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('80b3bdaa1f7ee393', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I accept a contribution from a professional corporation (P.C.)?', '["Can a doctor''s P.C. donate?","Are professional corps treated like regular corps?","Donations from professional associations"]', 'No. Professional corporations are subject to the same ban on political contributions as standard business corporations in Texas.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.091', 'Texas Election Code § 253.091', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('e92dc8971a50b93c', 'TX', '["state","district","county","local"]', 'finance_ethics', 'What is an ''in-kind'' contribution and do I report it?', '["How do I report donated goods?","If someone gives me flyers instead of money, what do I do?","Reporting non-monetary donations"]', 'An ''in-kind'' contribution is a non-monetary contribution of goods or services. You must report its fair market value on your campaign finance report as both a contribution and an expenditure.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – In-Kind FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('a0b3a1dfff6d8a43', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I use campaign funds for a victory party after the election?', '["Are election night parties a valid campaign expense?","Can I pay for a fundraiser with campaign money?","Social event spending rules"]', 'Yes. Campaign funds may be used for expenses associated with a candidate''s campaign-related fundraising or social events, including an election night celebration.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.035', 'Texas Election Code § 253.035', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('034f00b170479d44', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I accept contributions through Venmo or PayPal?', '["Are digital payments allowed for campaigns?","Can I use apps for fundraising?","Accepting donations via Venmo"]', 'Yes, provided that you collect all required contributor information (name, address, occupation, employer) and report the full amount received as the contribution, with any transaction fees reported as expenditures.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Electronic Payments FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('3b66fa31b0e7320e', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can a candidate for a non-judicial office accept a contribution from a judge?', '["Can judges donate to my campaign?","Judicial donation rules for non-judicial races","Are donations from the bench allowed?"]', 'Yes. While judges are subject to strict rules on their own fundraising, Texas law does not prohibit a non-judicial candidate from accepting a personal contribution from a judge.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Judicial FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to non-judicial candidates in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('537535b7c2596c78', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Can I offer a ''reward'' (like a raffle ticket) to people who show proof of voting?', '["Can I give away stuff to voters?","Is it legal to offer incentives for voting?","Can I hold a raffle for people who vote?"]', 'No. Both state and federal law prohibit offering anything of value in exchange for voting or for voting for or against a particular candidate.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.276.htm#276.013', 'Texas Election Code § 276.013', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and individuals in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('d0bfe965c787c6be', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I use campaign funds to pay for legal fees related to the campaign?', '["Can campaign money pay for a lawyer?","Is defending a lawsuit a campaign expense?","Paying for legal counsel with donor money"]', 'Yes. Campaign funds may be used for legal fees incurred in connection with the campaign or the duties of an officeholder, including defending against an ethics complaint.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.253.htm#253.035', 'Texas Election Code § 253.035', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('75b96e427f8279a3', 'TX', '["state","district","county","local"]', 'finance_ethics', 'What happens to my campaign funds if I decide to withdraw from the race?', '["Closing out a campaign account","Can I keep my donor money if I quit?","Rules for surplus campaign funds"]', 'Surplus funds must be used for campaign or officeholder purposes, returned to contributors, or donated to charity. You may not take the money for personal use.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.254.htm#254.203', 'Texas Election Code § 254.203', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('94bdaa3194d00dd6', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I accept a contribution from a partnership?', '["Can a law firm partnership donate?","Partnership donation rules in Texas","Are partnerships treated like corps?"]', 'Yes, but if the partnership has any corporate partners, the contribution must be attributed solely to the individual partners who are not corporations.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Partnership FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('64f1d66679096f9a', 'TX', '["state","district","county","local"]', 'ballot_access', 'Can I list my professional title (like ''Dr.'' or ''Senator'') on the ballot?', '["Using titles on the ballot","Can I put my job title next to my name?","Ballot name rules for incumbents"]', 'No. Under Texas law, a title or designation of a professional or social status may not be used on the ballot (e.g., ''Judge'', ''PhD'', ''Esq'' are prohibited).', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.52.htm#52.031', 'Texas Election Code § 52.031', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('38c6c410265885ac', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I accept a contribution from a state agency or university employee?', '["Donations from state employees","Can teachers at public schools donate?","Are public employees allowed to contribute?"]', 'Yes. State law does not prohibit public employees from making personal political contributions, though they are prohibited from using state resources to do so.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – State Employees FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates and officeholders in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('641a06526589bc62', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Is it legal to drive voters to the polls?', '["Can I run a ''Get Out the Vote'' shuttle?","Providing transportation to voters","Is it illegal to pay for someone''s ride to the polls?"]', 'Yes, but you cannot pay the voters to vote or pay drivers based on the number of voters they bring to the polls; it must be a volunteer or hourly-rate service.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.276.htm#276.013', 'Texas Election Code § 276.013', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns and individuals in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('e4a0881591f41d22', 'TX', '["federal","state","district","county","local"]', 'election_dates', 'When is the 2026 General Election?', '["What is the date for the November election?","When is election day 2026?","General election date Texas"]', 'The 2026 General Election for federal, state, and county officers is Tuesday, November 3, 2026.', 'https://www.sos.state.tx.us/elections/voter/important-election-dates.shtml', 'Texas Secretary of State – Important Election Dates', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all voters and candidates on the November ballot in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('19f065f147e30a45', 'TX', '["federal","state","district","county","local"]', 'election_dates', 'What is the voter registration deadline for the 2026 General Election?', '["When is the last day to register for November?","Registration deadline for general election","How late can someone register to vote?"]', 'The deadline to register to vote for the November 3, 2026 General Election is Monday, October 5, 2026.', 'https://www.sos.state.tx.us/elections/laws/advisory2026-03.shtml', 'Texas Secretary of State – Election Advisory', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all unregistered eligible voters in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('b6dc47ba1aa86900', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'What forms of ID are acceptable for a voter at the polls?', '["Voter ID rules in Texas","Do voters need a driver''s license to vote?","What ID can I tell my supporters to bring?"]', 'Voters must present one of seven acceptable forms of photo ID, which include a Texas Driver License, Texas Election Identification Certificate, Texas Personal Identification Card, Texas Handgun License, US Military ID card, US Citizenship Certificate with photo, or a US Passport.', 'https://www.votetexas.gov/mobile/id-faqs.htm', 'Texas Secretary of State – VoteTexas.gov ID FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all voters voting in person in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('74ad767d1a9cf307', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Can voters wear my campaign t-shirt into the polling place?', '["Are campaign shirts allowed when voting?","Apparel rules at polls","Can supporters wear hats with my name inside?"]', 'No. Wearing apparel (like t-shirts, hats, or buttons) that relates to a candidate, measure, or political party on the current ballot is considered electioneering and is prohibited within 100 feet of the polling place entrance.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.61.htm#61.003', 'Texas Election Code § 61.003', '2026-05-09', 'static', 'statute_citation', 'Applies to all voters and campaign supporters in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('e549779fdc417a32', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Can voters use their cell phones to look at my digital slate card while in the voting booth?', '["Cell phone rules at polling places","Can people read texts in the booth?","Are phones allowed for voting notes?"]', 'No. Texas law prohibits the use of wireless communication devices (like cell phones) within 100 feet of voting stations. Voters should bring written/printed notes instead.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.61.htm#61.014', 'Texas Election Code § 61.014', '2026-05-09', 'static', 'statute_citation', 'Applies to all voters inside polling locations.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('385298fc0a37cc28', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'When is the deadline to request a mail-in ballot for the November General Election?', '["Last day to apply for vote by mail","Mail ballot application deadline 2026","When do seniors need to request their ballots?"]', 'The deadline for the Early Voting Clerk to receive an Application for a Ballot by Mail (ABBM) is Friday, October 23, 2026. It must be received, not just postmarked, by this date.', 'https://www.sos.state.tx.us/elections/laws/advisory2026-03.shtml', 'Texas Secretary of State – Election Advisory', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all eligible vote-by-mail voters in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('46fcc1a9cfcb5938', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'What is the deadline for military and overseas voters to return their mail ballots?', '["FPCA ballot return deadlines","When are overseas military ballots due?","Military voting rules Texas"]', 'For the November General Election, mail ballots from active duty military or their family members mailed from outside the US must be postmarked by Election Day (Nov 3, 2026) and received by Monday, November 9, 2026.', 'https://www.sos.state.tx.us/elections/laws/advisory2026-03.shtml', 'Texas Secretary of State – Federal Voting Assistance Guidelines', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to military and overseas voters using the FPCA process.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('48598d9731594d39', 'TX', '["state","district","county","local"]', 'voter_interaction', 'How long does the Early Voting Ballot Board have to count provisional ballots?', '["When will provisional ballots be finalized?","Deadline for counting provisional votes","How many days after election day are provisional ballots verified?"]', 'For the general election for state and county officers, the early voting ballot board must verify and count provisional ballots no later than the 13th day after election day.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.65.htm#65.051', 'Texas Election Code § 65.051', '2026-05-09', 'static', 'statute_citation', 'Applies to post-election vote tabulation for state and local elections.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('954f2ea70d416ad7', 'TX', '["state"]', 'candidate_eligibility', 'How old do I have to be to run for Governor of Texas?', '["Age requirement for Texas Governor","Can a 25-year-old run for Governor?","Minimum age for the governor''s office"]', 'A candidate for Governor must be at least 30 years of age before the day of the election.', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/qualifications2026.shtml', 'Texas Secretary of State – Candidate Qualifications 2026', '2026-05-09', 'static', 'official_source_direct', 'Applies exclusively to candidates for Governor of Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('0f17287505114d63', 'TX', '["state","district"]', 'candidate_eligibility', 'How old do I have to be to run for the Texas State Senate?', '["Age requirement for State Senate","Minimum age to be a state senator","Can a 21-year-old run for the Texas Senate?"]', 'A candidate for the Texas State Senate must be at least 26 years of age.', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/qualifications2026.shtml', 'Texas Secretary of State – Candidate Qualifications 2026', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates for the Texas Senate.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('3b14366964af7817', 'TX', '["state","district"]', 'candidate_eligibility', 'How old do I have to be to run for the Texas House of Representatives?', '["Age requirement for State Rep","Minimum age to be a state representative","State House age rules"]', 'A candidate for the Texas House of Representatives must be at least 21 years of age.', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/qualifications2026.shtml', 'Texas Secretary of State – Candidate Qualifications 2026', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates for the Texas House of Representatives.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('ffd03eb2eaa24125', 'TX', '["state","district","county","local"]', 'candidate_eligibility', 'Can I run for two different offices in the same election?', '["Dual candidacy rules in Texas","Can I run for Mayor and State Rep at the same time?","Running for multiple seats on one ballot"]', 'No. Under Texas law, a candidate may not file applications for a place on the ballot for two or more offices that will be voted on at one or more elections held on the same day.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.141.htm#141.033', 'Texas Election Code § 141.033', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates attempting to run simultaneously for multiple offices.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('4ffbe3894e37a588', 'TX', '["state","district","county"]', 'candidate_eligibility', 'Do I automatically resign my current office if I run for a different office?', '["Resign to run laws Texas","Does running for another seat force me to quit?","Automatic resignation provisions"]', 'Yes, for certain offices. Under Article XVI, Section 65 of the Texas Constitution, if specific county or district officers announce their candidacy for another office with more than 1 year and 30 days left in their term, it constitutes an automatic resignation.', 'https://statutes.capitol.texas.gov/Docs/CN/htm/CN.16.htm#16.65', 'Texas Constitution, Article 16, § 65', '2026-05-09', 'static', 'statute_citation', 'Applies specifically to District Clerks, County Clerks, County Judges, Sheriffs, and other designated county/district officers.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('6546faeb1814f14b', 'TX', '["state","district","county","local"]', 'ballot_access', 'When is the deadline to file as a write-in candidate for the General Election?', '["General election write-in deadline","How late can I file to be a write-in?","Declaration of write-in candidacy due date"]', 'A Declaration of Write-In Candidacy must be filed no later than 5:00 p.m. of the 78th day before general election day.', 'https://www.sos.state.tx.us/elections/forms/pol-sub/2-26.pdf', 'Texas Secretary of State – Declaration of Write-In Candidacy', '2026-05-09', 'static', 'official_source_direct', 'Applies to all individuals seeking write-in status for the November General Election.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('31d7e10f67c2ed7f', 'TX', '["state","district","county","local"]', 'ballot_access', 'If I want to withdraw from the election, when is the deadline to have my name removed from the ballot?', '["How do I get my name off the ballot?","Withdrawal deadline","Can I quit the race and be removed?"]', 'To withdraw and have your name removed from the ballot, a signed and acknowledged written request must be timely filed with the appropriate authority; specific deadlines vary by election type but are strictly enforced by the Election Code.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.145.htm#145.001', 'Texas Election Code § 145.001', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates wishing to withdraw their candidacy.', 'batch_2026-05-09T18-59-07_texas_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('5e5862c796361ee6', 'TX', '["state","district","county","local"]', 'ballot_access', 'What happens if a candidate dies after their name is certified for the ballot?', '["Deceased candidate on ballot","What if a candidate dies before election day?","Can a dead person''s name be removed?"]', 'If a deceased candidate''s name has already been certified by the Secretary of State, it may not be omitted from the ballot without explicit authorization from the Secretary of State.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.145.htm#145.002', 'Texas Election Code § 145.002', '2026-05-09', 'static', 'statute_citation', 'Applies to election authorities handling the ballots of deceased candidates.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('95dd157b7d075af8', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Can I use a megaphone or speaker system to campaign outside the polling place?', '["Sound amplification rules at polls","Can I play music outside a voting location?","Distance for using loudspeakers"]', 'No. Texas law prohibits using a sound amplification device to campaign or electioneer within 1,000 feet of a building where a polling place is located.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.61.htm#61.004', 'Texas Election Code § 61.004', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaigns, supporters, and individuals near polling locations.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('19a88b8f8c7bac7f', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Can a voter bring an assistant into the voting booth?', '["Assisting voters rules","Can a spouse help a voter in the booth?","Who can help someone vote?"]', 'Yes. A voter may be assisted by any person of their choice, except their employer, an agent of their employer, or an officer/agent of their labor union, provided the voter is physically unable to read or mark the ballot.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.64.htm#64.032', 'Texas Election Code § 64.032', '2026-05-09', 'static', 'statute_citation', 'Applies to all voters requiring assistance and the individuals assisting them.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('18119abdd2eaafb1', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Can a voter with a handgun license carry their firearm into the polling place?', '["Guns at polling places","Can I carry concealed when voting?","Are firearms allowed in election centers?"]', 'No. Texas law specifically prohibits intentionally, knowingly, or recklessly possessing a firearm on the premises of a polling place on the day of an election or while early voting is in progress.', 'https://statutes.capitol.texas.gov/Docs/PE/htm/PE.46.htm#46.03', 'Texas Penal Code § 46.03', '2026-05-09', 'static', 'statute_citation', 'Applies to all individuals at polling locations, including licensed handgun carriers.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('a7a36564d6553ef7', 'TX', '["judicial"]', 'ballot_access', 'Do judicial candidates run in partisan elections in Texas?', '["Are judge races partisan?","Do judges run as Republicans or Democrats?","Partisan labels for judicial candidates"]', 'Yes. Texas is one of the states where trial and appellate court judges are elected on partisan ballots, meaning candidates run as nominees of political parties (e.g., Republican or Democrat).', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/qualifications2026.shtml', 'Texas Secretary of State – Candidate Qualifications', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates for District, Appellate, and Supreme Court judicial offices.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('20b8d1a65d25fe27', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can a candidate serve as their own campaign treasurer?', '["Do I have to hire a treasurer?","Can I be my own treasurer?","Self-appointed campaign treasurer"]', 'Yes. Under Texas law, a candidate may appoint themselves as their own campaign treasurer when filing the Form CTA.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Treasurer FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates required to file a campaign treasurer appointment.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('0eeccbf1ed0148d6', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I use campaign funds to pay a fine assessed by the Ethics Commission?', '["Paying TEC fines with donor money","Are ethics fines a campaign expense?","Can campaign accounts pay penalties?"]', 'No. You cannot use political contributions to pay a penalty assessed by the Texas Ethics Commission.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Permissible Expenditures FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates and officeholders subject to TEC fines.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('ee6c2160cf725f48', 'TX', '["federal","state","district","county","local"]', 'ballot_access', 'Is straight-ticket voting allowed in Texas?', '["Can voters punch one button for all Republicans?","Is straight-party voting still an option?","Straight ticket ballot option"]', 'No. Straight-ticket voting was eliminated in Texas. Voters must mark their choice for each individual race on the ballot.', 'https://www.votetexas.gov/voting-in-texas/index.html', 'Texas Secretary of State – VoteTexas.gov', '2026-05-09', 'static', 'official_source_direct', 'Applies to all voters and campaigns in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('ad967eace0bab729', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Can I appoint poll watchers to observe the voting process?', '["How do I get poll watchers into a voting center?","Rules for campaign observers","Appointing poll watchers"]', 'Yes. A candidate whose name appears on the ballot may appoint up to two poll watchers per precinct or polling place to observe the conduct of the election.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.33.htm#33.002', 'Texas Election Code § 33.002', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates with names on the ballot.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('4654704b9ff26e4a', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'What qualifications must a poll watcher meet?', '["Who can be a poll watcher?","Requirements for election observers","Can I hire anyone to be a poll watcher?"]', 'A poll watcher must be a registered voter of the territory (e.g., county or city) where the election is held and must possess a certificate of appointment.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.33.htm#33.031', 'Texas Election Code § 33.031', '2026-05-09', 'static', 'statute_citation', 'Applies to individuals seeking to act as poll watchers.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('9340648557d7a4ac', 'TX', '["state","district","county"]', 'redistricting', 'If my district boundaries change during redistricting, do I adopt the new or old district lines for residency?', '["Redistricting map residency","Which lines count for my residency requirement?","How do new maps affect where I have to live?"]', 'You must reside in the territory of the newly drawn district for the required period preceding the election, but time lived in that physical area prior to the new lines taking effect counts toward your continuous residency.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.141.htm#141.001', 'Texas Election Code § 141.001', '2026-05-09', 'static', 'statute_citation', 'Applies to candidates running in newly redistricted areas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('98ec69de82168c70', 'TX', '["state"]', 'redistricting', 'How is a vacancy in the State Legislature filled?', '["What happens if a state rep resigns?","Special elections for state legislature vacancies","Filling an empty senate seat"]', 'A vacancy in the Texas Legislature must be filled by a special election called by the Governor; there is no appointment process for legislative vacancies in Texas.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.203.htm#203.002', 'Texas Election Code § 203.002', '2026-05-09', 'static', 'statute_citation', 'Applies to vacancies in the Texas House of Representatives and Texas Senate.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('44007f240e57ffb1', 'TX', '["federal","state"]', 'redistricting', 'How is a vacancy for a United States Senator from Texas filled?', '["What if a US Senator dies or resigns?","Appointing a new US Senator","US Senate vacancy rules Texas"]', 'If a vacancy occurs for a U.S. Senator, the Governor of Texas may appoint a person to fill the vacancy temporarily until a special election is held to fill the unexpired term.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.204.htm#204.002', 'Texas Election Code § 204.002', '2026-05-09', 'static', 'statute_citation', 'Applies exclusively to U.S. Senate vacancies from Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('2c589fa08b80a417', 'TX', '["county","local"]', 'redistricting', 'Are candidates for county and city offices subject to recall elections in Texas?', '["Can a mayor be recalled?","Recall laws in Texas for local officials","Removing a city council member"]', 'Texas law does not provide for the recall of state or county officers. However, home-rule municipalities may include provisions for recalling city officials in their individual city charters.', 'https://www.sos.state.tx.us/elections/laws/faq-on-local-candidacy.shtml', 'Texas Secretary of State – Local Candidacy FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to local officials in home-rule municipalities.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('1ea0cf05a7ca6dbd', 'TX', '["state","district","county"]', 'finance_ethics', 'If I declare my candidacy, do I have to file a Personal Financial Statement?', '["PFS requirements for candidates","Do I have to disclose my personal wealth?","Filing a Personal Financial Statement"]', 'Yes. Candidates for state offices, as well as certain district and county offices, must file a Personal Financial Statement (PFS) with the Texas Ethics Commission detailing their personal financial interests.', 'https://www.ethics.state.tx.us/forms/pfs/pfsfrm.php', 'Texas Ethics Commission – Personal Financial Statements', '2026-05-09', 'static', 'official_source_direct', 'Applies to state and specific county/district candidates subject to TEC oversight.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('509212d1570aa12d', 'TX', '["federal","state","district","county","local"]', 'ballot_access', 'How is the order of candidate names on the ballot determined?', '["Who gets the top spot on the ballot?","Ballot order drawing rules","How are names randomized on ballots?"]', 'The order of candidates'' names on the ballot for a primary or general election is determined by a public drawing conducted by the appropriate election authority.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.52.htm#52.094', 'Texas Election Code § 52.094', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates appearing on a Texas ballot.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('a6b0f0b0871a20cb', 'TX', '["state","district","county","local"]', 'finance_ethics', 'What is considered an ''independent expenditure''?', '["What makes a PAC expenditure independent?","Coordinated vs independent spending","Super PAC spending rules"]', 'An independent expenditure is a campaign communication that expressly advocates the election or defeat of a clearly identified candidate, made without any prior consent, coordination, or consultation with the candidate or their campaign.', 'https://www.ethics.state.tx.us/resources/advertising/PolAd_Guide.php', 'Texas Ethics Commission – Political Advertising Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to PACs, groups, and campaigns operating in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('485aa63605f9dc03', 'TX', '["state","district"]', 'residency', 'What is the difference between a ''domicile'' and a ''residence'' for running for office?', '["Can I have two residences?","Domicile vs residence","Does my vacation home count as a residence?"]', 'For voting and candidacy purposes, ''residence'' means domicile, which is defined as one''s home and fixed place of habitation to which they intend to return after any temporary absence. You can have multiple houses, but only one legal domicile.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.1.htm#1.015', 'Texas Election Code § 1.015', '2026-05-09', 'static', 'statute_citation', 'Applies to all candidates establishing residency for eligibility.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('34cc972d58965ce8', 'TX', '["state","district","county","local"]', 'ballot_access', 'Can I gather petition signatures before I file my campaign treasurer appointment?', '["When can I start collecting signatures?","Do I need a CTA before circulating petitions?","Signature gathering timeline"]', 'Yes. Gathering petition signatures is not considered a campaign expenditure or contribution under Texas law, so you may collect signatures prior to filing a Campaign Treasurer Appointment.', 'https://www.ethics.state.tx.us/resources/FAQs/FAQ_COH_Legal.php', 'Texas Ethics Commission – Campaign Treasurer FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to candidates utilizing the petition method for ballot access.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('bcd8ecd676bc9556', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'Can a voter mail their ballot in the same envelope as their spouse''s ballot?', '["Can we mail two ballots in one envelope?","Household ballot mailing rules","Submitting multiple ballots by mail"]', 'No. Each voter''s ballot must be sealed in its own official carrier envelope, signed individually, and mailed separately to the early voting clerk.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.86.htm#86.006', 'Texas Election Code § 86.006', '2026-05-09', 'static', 'statute_citation', 'Applies to all voters utilizing the vote-by-mail process.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('62e7ffeaeb03d70e', 'TX', '["federal"]', 'ballot_access', 'What is the filing fee for a U.S. Senator in Texas?', '["How much to run for Senate?","US Senate filing fee","Cost to get on the ballot for US Senate"]', 'The filing fee for a candidate for nomination in the general primary election for United States Senator is $5,000.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.172.htm#172.024', 'Texas Election Code § 172.024', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates for U.S. Senate in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('8383dc15b3673ddc', 'TX', '["state"]', 'ballot_access', 'What is the filing fee for a statewide office like Governor?', '["How much is the filing fee for Governor?","Statewide candidate fees","Cost to run for a statewide seat"]', 'The filing fee for a candidate for a statewide elected office (such as Governor, Lt. Governor, or Attorney General), except for U.S. Senator, is $3,750.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.172.htm#172.024', 'Texas Election Code § 172.024', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates for statewide offices other than U.S. Senate.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('79252335612ee5f7', 'TX', '["federal"]', 'ballot_access', 'What is the filing fee for a U.S. Representative?', '["Congressional filing fee","How much does it cost to run for US House?","Cost to get on the ballot for Congress"]', 'The filing fee for a candidate for nomination in the general primary election for United States Representative is $3,125.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.172.htm#172.024', 'Texas Election Code § 172.024', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates for the U.S. House of Representatives in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('f05e5c5484cfc52e', 'TX', '["state","district"]', 'ballot_access', 'What is the filing fee to run for the Texas State Senate?', '["How much is the State Senate filing fee?","Cost to run for state senator","Fee to get on the ballot for TX Senate"]', 'The filing fee for a candidate for nomination in the general primary election for Texas State Senator is $1,250.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.172.htm#172.024', 'Texas Election Code § 172.024', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates for the Texas State Senate.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('d646d6e165e48c6c', 'TX', '["state","district"]', 'ballot_access', 'What is the filing fee to run for the Texas State House?', '["State Rep filing fee","How much does it cost to run for State House?","Cost to get on the ballot for TX Rep"]', 'The filing fee for a candidate for nomination in the general primary election for Texas State Representative is $750.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.172.htm#172.024', 'Texas Election Code § 172.024', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates for the Texas House of Representatives.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('b4c956f09099cbda', 'TX', '["state"]', 'ballot_access', 'What is the filing fee for the State Board of Education?', '["SBOE filing fee","Cost to run for State Board of Education","How much is the fee for SBOE?"]', 'The filing fee for a candidate for nomination in the general primary election for a member of the State Board of Education is $300.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.172.htm#172.024', 'Texas Election Code § 172.024', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to all candidates for the State Board of Education.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('0b9fbd551c49dbdb', 'TX', '["judicial"]', 'ballot_access', 'What is the filing fee for a district judge?', '["How much does it cost to run for judge?","District judge filing fee","Cost to get on the ballot for district court"]', 'The standard filing fee for a district judge is $1,500, but it increases to $2,500 for a district or criminal district judge of a court wholly contained in a county with a population of more than 1.5 million.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.172.htm#172.024', 'Texas Election Code § 172.024', '2026-05-09', 'per_cycle', 'statute_citation', 'Applies to candidates for district court judgeships.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('1cf7d35cbab14ad7', 'TX', '["state","district","county","local"]', 'ballot_access', 'Can I submit my filing fee and application via email or fax?', '["Can I fax my application and fee?","Emailing candidate filing materials","How to submit the filing fee remotely"]', 'No. If a candidate submits a filing fee along with an application, it may NOT be submitted via email or fax; it must be delivered in person or by mail. However, an application accompanied by a petition in lieu of a filing fee *can* be emailed or faxed.', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/faqs.shtml', 'Texas Secretary of State – Candidacy FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates submitting a filing fee.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('0e0a613299b23adf', 'TX', '["state","district","county","local"]', 'ballot_access', 'Can I have someone else drop off my application and filing fee?', '["Can my campaign manager file for me?","Having someone else deliver my application","Can a proxy drop off my paperwork?"]', 'Yes. As long as the candidate application is completed, signed, and notarized, and accompanied by either a filing fee or petition, another person may deliver the application to the filing authority on the candidate''s behalf.', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/faqs.shtml', 'Texas Secretary of State – Candidacy FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates filing an application for a place on the ballot.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('e76206515a352d8d', 'TX', '["state","district","county","local"]', 'ballot_access', 'Can I use an online notary for my candidate application?', '["Online notarization for candidate app","Can I notarize my filing paperwork over Zoom?","Using a remote notary"]', 'Yes, if the notary is authorized to perform online notarizations and they add the required online notarial statement to the candidate application.', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/faqs.shtml', 'Texas Secretary of State – Candidacy FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates needing their application notarized.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('9a9fa5bbd7642e2a', 'TX', '["federal","state","district","county","local"]', 'election_dates', 'When can a voter start requesting a mail-in ballot for a 2026 election?', '["When is the earliest I can apply for a mail ballot?","First day to request a ballot by mail","When does the state start accepting mail ballot apps?"]', 'The first day to apply for a ballot by mail using an Application for a Ballot by Mail (ABBM) or a Federal Postcard Application (FPCA) for the 2026 election year was Thursday, January 1, 2026.', 'https://www.sos.state.tx.us/elections/voter/important-election-dates.shtml', 'Texas Secretary of State – Important Election Dates', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all voters eligible to vote by mail.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('62d149fafe5f9f52', 'TX', '["state","district","county","local"]', 'finance_ethics', 'What is the difference between a campaign account and an officeholder account?', '["Do I need a separate account once I win?","Officeholder vs campaign account","Can I use my campaign account for officeholder expenses?"]', 'Title 15 of the Election Code regulates both campaign and officeholder funds, but you do not need separate bank accounts; a candidate/officeholder may keep political contributions in one account and use them for either campaign or officeholder expenditures.', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to all elected officeholders who were previously candidates.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('83ade567de02cbe5', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I use political contributions to buy or rent real property for my campaign?', '["Using campaign funds for real estate","Can my campaign buy a building?","Renting office space with donor money"]', 'You may use political contributions to *rent* real property for campaign or officeholder purposes, but you are strictly prohibited from using political contributions to *purchase* real property.', 'https://www.ethics.state.tx.us/data/resources/judicial/jcoh_guide26.pdf', 'Texas Ethics Commission – Judicial COH Guide (Applies Generally)', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates and officeholders.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('0e8e6d52fccf8e7b', 'TX', '["federal","state","district","county","local"]', 'ballot_access', 'How are the offices ordered on the general election ballot?', '["Who goes first on the ballot?","Ballot order by office level","Why is the President at the top?"]', 'Texas Election Code § 52.092 dictates the strict order: Federal offices (President, Senate, House) appear first, followed by Statewide state offices (Governor, Lt. Gov), District state offices (State Senate, State Rep), County offices, and finally Precinct offices.', 'https://texas.public.law/statutes/tex._election_code_section_52.092', 'Texas Election Code § 52.092', '2026-05-09', 'static', 'statute_citation', 'Applies to all general election ballots in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('f23910739050aa25', 'TX', '["state","district","county","local"]', 'finance_ethics', 'If I am a candidate, do I file the ''Form C/OH''?', '["What form do I use for finance reports?","Candidate/Officeholder Campaign Finance Report","Which Ethics form do I need to file?"]', 'Yes. The ''Candidate/Officeholder Campaign Finance Report'' (Form C/OH) is the standard form used by all candidates and officeholders to report political contributions and expenditures.', 'https://www.ethics.state.tx.us/forms/COH/COHindex.php', 'Texas Ethics Commission – Form C/OH Instructions', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates and officeholders required to report finances.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('e35edd792eb3ac01', 'TX', '["state"]', 'redistricting', 'Can the Governor call a special election to fill a vacancy in the State House?', '["Who orders a special election for a state rep?","Filling a vacancy in the legislature","Special election order authority"]', 'Yes. A vacancy in the Texas Legislature must be filled by a special election ordered by the Governor.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.203.htm#203.002', 'Texas Election Code § 203.002', '2026-05-09', 'static', 'statute_citation', 'Applies to vacancies in the Texas House and Senate.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('c5dfd437d72090d1', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I accept a contribution from a political committee (PAC) that is located out-of-state?', '["Out-of-state PAC donations","Can I take money from a federal PAC?","Rules for out of state committee contributions"]', 'Yes, but if the out-of-state political committee contributes more than $1,140 in a reporting period, you must obtain a certified statement from them detailing their contributors or a copy of their FEC statement of organization before accepting it.', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates accepting funds from non-Texas PACs.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('9145b325df40b0da', 'TX', '["federal","state","district","county","local"]', 'ballot_access', 'Does my candidate application need to be notarized?', '["Do I need a notary for my filing forms?","Notarizing the application for a place on the ballot","Who can swear in my candidate app?"]', 'Yes. An application for a place on the ballot must be notarized or otherwise sworn to before someone authorized to administer an oath under Texas law prior to filing.', 'https://www.sos.state.tx.us/elections/candidates/guide/2026/faqs.shtml', 'Texas Secretary of State – Candidacy FAQ', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates filing an application.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('45ea341268b31f6d', 'TX', '["federal","state","district","county","local"]', 'election_dates', 'When does early voting start for the November 2026 General Election?', '["First day of early voting for general election","Early voting dates November 2026","When can voters start voting in person for the fall?"]', 'The first day of early voting by personal appearance for the November 3, 2026, General Election is Monday, October 19, 2026.', 'https://www.sos.state.tx.us/elections/voter/important-election-dates.shtml', 'Texas Secretary of State – Important Election Dates', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all voters and campaigns in the general election.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('e4b9f18c4536f7c4', 'TX', '["federal","state","district","county","local"]', 'election_dates', 'When does early voting end for the November 2026 General Election?', '["Last day of early voting November 2026","When does early voting close for the general?","Final day to vote early in the fall"]', 'The last day of early voting by personal appearance for the November 3, 2026, General Election is Friday, October 30, 2026.', 'https://www.sos.state.tx.us/elections/voter/important-election-dates.shtml', 'Texas Secretary of State – Important Election Dates', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to all voters and campaigns in the general election.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('8113f2269858d4b9', 'TX', '["federal","state","district","county","local"]', 'voter_interaction', 'If a mail-in ballot is postmarked by 7 PM on Election Day, when is the deadline for the county to receive it?', '["Mail ballot receipt deadline","How late can a postmarked ballot arrive?","Grace period for mail ballots"]', 'If a carrier envelope is postmarked by 7:00 p.m. at the location of the election on Election Day, it must be received by 5:00 p.m. on the next business day after Election Day to be counted.', 'https://www.sos.state.tx.us/elections/voter/important-election-dates.shtml', 'Texas Secretary of State – Important Election Dates', '2026-05-09', 'static', 'official_source_direct', 'Applies to all domestic civilian vote-by-mail ballots.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('23d16a0fd4643ac6', 'TX', '["state","district","county","local"]', 'finance_ethics', 'If I loan my campaign personal funds, do I report it as a contribution?', '["How to report a personal loan","Reporting candidate loans to the campaign","Do loans count as contributions?"]', 'A loan from personal funds must be reported as a loan. It is not reported as a political contribution, but you must report the expenditure of those funds as a political expenditure made from personal funds.', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates loaning money to their campaigns.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('290a66164dd2621b', 'TX', '["state","district","county","local"]', 'finance_ethics', 'When does the ''reporting period'' for a campaign finance report end?', '["What dates does the finance report cover?","When does the reporting window close?","Cutoff date for TEC reports"]', 'The period covered by a report ends on the date specified by the filing schedule (e.g., June 30 for the July semiannual report, or the 25th day before the election for a pre-election report).', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to all filers of the Form C/OH.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('ca392dc9d191e31c', 'TX', '["state","district","county","local"]', 'finance_ethics', 'If a filing deadline falls on a weekend, when is the report actually due?', '["Weekend filing deadlines","Is my report due on Sunday or Monday?","Holiday filing extensions"]', 'If the due date for a report falls on a Saturday, Sunday, or legal state or national holiday, the report is due on the next regular business day.', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to all TEC filing deadlines.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('460699c110e49b70', 'TX', '["state","district","county","local"]', 'finance_ethics', 'What time of day are campaign finance reports due?', '["Deadline hour for TEC reports","Is the report due at midnight or 5 PM?","Filing cutoff time"]', 'The deadline for filing a campaign finance report is 5:00 p.m. on the due date.', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to all TEC filing deadlines.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('39b664e2acff4691', 'TX', '["state","district","county","local"]', 'finance_ethics', 'Can I file a ''modified'' report to avoid filing pre-election reports?', '["What is modified reporting?","How to skip the 8-day and 30-day reports","Filing the short form report"]', 'Yes. If you declare on your Form CTA that you do not intend to accept more than $1,010 in political contributions or make more than $1,010 in political expenditures in connection with an election, you can choose modified reporting and avoid the pre-election reports.', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'per_cycle', 'official_source_direct', 'Applies to candidates running low-budget campaigns.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('bc812dee20b810c0', 'TX', '["federal","state","district"]', 'redistricting', 'Did Texas redraw its congressional map for the 2026 elections?', '["Are the congressional districts different in 2026?","Did the legislature pass a new map?","2026 redistricting map status"]', 'Yes. Texas passed a new congressional map (PlanC2333) in 2025. After litigation, the U.S. Supreme Court ruled on December 4, 2025, that Texas could use the newly drawn 2025 map for the 2026 elections.', 'https://ballotpedia.org/Redistricting_in_Texas_ahead_of_the_2026_elections', 'Ballotpedia – Redistricting in Texas 2026', '2026-05-09', 'volatile', 'secondary_source', 'Applies to all candidates and voters in Texas Congressional districts.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('3d71a788bb366e8b', 'TX', '["state","district","county","local"]', 'ballot_access', 'When does a candidate file their ''Final Report''?', '["How do I close my campaign account?","Filing the final TEC report","Ending my campaign reporting obligations"]', 'A candidate may file a Final Report at any time they have zero unexpended political contributions, zero unexpended interest/income, and zero retained assets purchased with political funds, and they do not intend to accept any more contributions or make any more expenditures.', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to all candidates wishing to terminate their campaign treasurer appointment.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('ff7bddfaac92cca4', 'TX', '["state","district","county","local"]', 'ballot_access', 'If I lose my election but still have campaign money, what reports do I have to file?', '["Reporting requirements after losing","Do I still file reports if I lost?","Unexpended contributions report"]', 'If you are no longer an officeholder or a candidate but retain political contributions, you must file an Annual Report of Unexpended Contributions by January 15 of each year until the funds are disposed of and a Final Disposition report is filed.', 'https://www.ethics.state.tx.us/data/resources/guides/coh_local_guide.pdf', 'Texas Ethics Commission – Local COH Guide', '2026-05-09', 'static', 'official_source_direct', 'Applies to former candidates and officeholders with remaining funds.', 'batch_2026-05-09T18-59-07_texas_full_v1'),
  ('b4e4f197c5fa746c', 'TX', '["federal","state","district","county","local"]', 'ballot_access', 'Where can the public view a candidate''s campaign finance reports?', '["Are campaign finance reports public?","Where do I look up my opponent''s donors?","Public posting of TEC reports"]', 'Pursuant to HB 2626 (codified as Election Code § 254.04011), all political subdivisions are required to post all campaign finance reports filed on or after September 1, 2023, on their respective websites.', 'https://statutes.capitol.texas.gov/Docs/EL/htm/EL.254.htm#254.04011', 'Texas Election Code § 254.04011', '2026-05-09', 'static', 'statute_citation', 'Applies to all campaign finance reports filed in Texas.', 'batch_2026-05-09T18-59-07_texas_full_v1')
